import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"Guide: AI Guardrails & Security","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/ai-guardrails-security.md","filePath":"guides/ai-guardrails-security.md","lastUpdated":1782929962000}'),i={name:"guides/ai-guardrails-security.md"};function s(n,t,o,l,c,g){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-ai-guardrails-security" tabindex="-1">Guide: AI Guardrails &amp; Security <a class="header-anchor" href="#guide-ai-guardrails-security" aria-label="Permalink to &quot;Guide: AI Guardrails &amp; Security&quot;">​</a></h1><p><strong>Decision:</strong> What automatically blocks unsafe code and unsafe AI usage?</p><p><strong>Classic validators (linters, SAST, SCA, secrets):</strong> see dedicated <a href="./static-analysis-linting.html">Guide: Linters &amp; static analysis</a>. <strong>Secret storage, IAM, RBAC, rotation:</strong> <a href="./identity-access-secrets.html">Guide: Identity, access &amp; secrets</a>. This guide covers security <strong>policy</strong> and <strong>AI-specific</strong> guardrails.</p><p>Related: <a href="./../qa-guardrails.html">qa-guardrails.md</a> · <a href="./static-analysis-linting.html">static-analysis-linting.md</a> · <a href="./identity-access-secrets.html">identity-access-secrets.md</a> · <a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a> · <a href="./../sops/SOP-012-exception-handling.html">SOP-012</a></p><hr><h2 id="pre-merge-guardrails" tabindex="-1">Pre-merge guardrails <a class="header-anchor" href="#pre-merge-guardrails" aria-label="Permalink to &quot;Pre-merge guardrails&quot;">​</a></h2><p>For linters, formatters, type checkers, SAST, SCA, IaC scanners, and pre-commit setup — see <strong><a href="./static-analysis-linting.html">Linters &amp; static analysis</a></strong>.</p><table tabindex="0"><thead><tr><th>Control</th><th>Options</th><th>See also</th></tr></thead><tbody><tr><td><strong>Secret scan</strong></td><td>gitleaks, GitGuardian, TruffleHog</td><td><a href="./static-analysis-linting.html">static-analysis-linting.md</a></td></tr><tr><td><strong>SAST</strong></td><td>Semgrep, CodeQL, Checkmarx</td><td>Same</td></tr><tr><td><strong>SCA</strong></td><td>Snyk, Dependabot, AWS Inspector</td><td>Same</td></tr><tr><td><strong>Container scan</strong></td><td>Trivy, ECR native</td><td>Same</td></tr><tr><td><strong>Policy as code</strong></td><td>OPA, Cedar, Conftest</td><td>Same + ADR-linked deny messages</td></tr><tr><td><strong>AI PR review</strong></td><td>Bugbot, CodeGuru Reviewer</td><td>Below — advisory vs blocking</td></tr></tbody></table><hr><h2 id="ai-review-advisory-vs-blocking" tabindex="-1">AI review: advisory vs blocking <a class="header-anchor" href="#ai-review-advisory-vs-blocking" aria-label="Permalink to &quot;AI review: advisory vs blocking&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Advisory</strong></td><td>Low friction</td><td>Teams ignore comments</td></tr><tr><td><strong>Blocking on severity</strong></td><td>Forces fix</td><td>Tuning required</td></tr><tr><td><strong>Blocking on custom rules</strong></td><td>Policy-aligned</td><td>Maintenance</td></tr></tbody></table><p><strong>Recommended:</strong> Blocking for secrets/SAST Critical; AI review advisory until tuned, then blocking for agreed rules.</p><hr><h2 id="ai-data-handling" tabindex="-1">AI data handling <a class="header-anchor" href="#ai-data-handling" aria-label="Permalink to &quot;AI data handling&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Policy element</th><th>Strict</th><th>Loose</th></tr></thead><tbody><tr><td>Prod PII in prompts</td><td>Never</td><td><strong>Pitfall:</strong> inevitable breach</td></tr><tr><td>Enterprise AI license</td><td>Required</td><td>Consumer tools</td></tr><tr><td>Prompt logging</td><td>Audited sample</td><td>No visibility</td></tr><tr><td>Local models on corp code</td><td>Discouraged</td><td>Uncontrolled leakage risk</td></tr></tbody></table><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>AI review replaces human review</strong></td><td>Subtle bugs and design issues ship</td><td>Human reviewer always for T1/T2</td></tr><tr><td><strong>Scan fatigue</strong></td><td>Teams request exceptions constantly</td><td>Fix root cause; tune rules</td></tr><tr><td><strong>Permanent exceptions</strong></td><td>Policy becomes meaningless</td><td>Time-bound exceptions (SOP-012)</td></tr><tr><td><strong>Secrets in AI-generated code</strong></td><td>Merge despite scan if review skipped</td><td>pre-commit + CI</td></tr><tr><td><strong>OPA policies disconnected from ADRs</strong></td><td>Devs don&#39;t understand denials</td><td>Link deny message to ADR ID</td></tr><tr><td><strong>No audit of AI prompts</strong></td><td>Insider data exfiltration undetected</td><td>Enterprise gateway logging</td></tr><tr><td><strong>Blocking AI review day one</strong></td><td>Developers disable or bypass</td><td>Start advisory; tighten gradually</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>pre-commit secrets → CI SAST/SCA/container → OPA on IaC → human PR review → AI review advisory → SEC owns data-in-AI policy.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./ai-coding-tools.html">AI coding tools</a> · <a href="./human-in-the-loop-governance.html">Human-in-the-loop</a></li></ul>',24)])])}const m=e(i,[["render",s]]);export{u as __pageData,m as default};
